"""
Represents the Checkers board and handles board operations.
"""

class Board:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for row in range(3):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = Piece('white')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('black')

    def print_board(self):
        # Print the board in a readable format
        for row in self.board:
            print(" ".join([str(piece if piece else '   ') for piece in row]))

    def get_piece(self, x, y):
        return self.board[x][y]

    def set_piece(self, x, y, piece):
        self.board[x][y] = piece

    def move_piece(self, start_x, start_y, end_x, end_y):
        # Move a piece from start position to end position
        piece = self.get_piece(start_x, start_y)
        self.set_piece(end_x, end_y, piece)
        self.set_piece(start_x, start_y, None)

    def capture_piece(self, start_x, start_y, end_x, end_y):
        # Capture a piece at the specified position
        self.set_piece((start_x + end_x) // 2, (start_y + end_y) // 2, None)
```

