"""
Utility functions for converting between notation and board coordinates.
"""

def parse_notation(notation):
    # Convert notation (e.g., 'a2') to board coordinates (e.g., (1, 0))
    letter_to_num = {chr(i): i - ord('a') for i in range(ord('a'), ord('i'))}
    num_to_letter = {i - ord('a'): chr(i) for i in range(ord('a'), ord('i'))}
    x = letter_to_num[notation[0].lower()]
    y = int(notation[1]) - 1
    return x, y

def to_notation(x, y):
    # Convert board coordinates (e.g., (1, 0)) to notation (e.g., 'a2')
    letter_to_num = {i: chr(i) for i in range(ord('a'), ord('i'))}
    num_to_letter = {chr(i): i - ord('a') for i in range(ord('a'), ord('i'))}
    return f"{num_to_letter[x]}{y + 1}"
