    def capture_moves(self, board, position):
        moves = []
        directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
        for dr, dc in directions:
            r, c = position
            if 0 <= r + 2 * dr < 8 and 0 <= c + 2 * dc < 8 and board[r + dr][c + dc] == ' ' and board[r + dr // 2][c + dc // 2] != self.color:
