    def move_to(self, board, from_pos, to_pos):
        fr, fc = from_pos
        tr, tc = to_pos

        if abs(fr - tr) == 1 and abs(fc - tc) == 1:
            board[fr][fc], board[tr][tc] = board[tr][tc], board[fr][fc]
            return True

